toolArgs.file_text:
.message-bubble {
    padding: 8px 16px;
    position: relative;
    transition: background-color 0.1s;
    border-radius: 4px;
}

.message-bubble:hover {
    background-color: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #1a1a1a;
}

.timestamp {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.45;
    color: #333;
    word-break: break-word;
}

.reactions-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    padding: 2px 8px;
    background-color: #eef1f5;
    border: 1px solid #d8dde3;
    border-radius: 12px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background-color: #dce3ed;
}

.thread-link {
    margin-top: 4px;
    font-size: 0.8rem;
    color: #4a90d9;
    cursor: pointer;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

.hover-actions {
    position: absolute;
    top: -14px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    cursor: pointer;
    font-size: 0.78rem;
    padding: 4px 8px;
    border-radius: 4px;
    color: #555;
    white-space: nowrap;
}

.action-btn:hover {
    background-color: #f0f0f0;
}

.emoji-picker-wrapper {
    position: relative;
}

.emoji-picker {
    position: absolute;
    top: 100%;
    right: 0;
    display: flex;
