arguments.file_text:
.chat-layout {
    height: 100vh;
    width: 100vw;
    overflow: hidden;
}

@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_fb022e9ec733486b81527a0f99d20a8a.Services
@using sv_fb022e9ec733486b81527a0f99d20a8a.Components.Chat
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <div class="sidebar-col">
        <ChannelSidebar Channels="channels"
                        SelectedChannelId="selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-col @(isThreadOpen ? "with-thread" : "")">
        @if (selectedChannel is not null)
        {
            <MessageArea @ref="messageAreaRef"
                         ChannelName="@selectedChannel.Name"
                         ChannelDescription="@selectedChannel.Description"
                         Messages="messages"
                         ThreadReplyCounts="threadReplyCounts"
                         IsLoadingMore="isLoadingMore"
                         OnLoadMore="LoadMoreMessages"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction"
                         OnSendMessage="SendMessage" />
        }
        else
        {
            <div class="empty-state">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (isThreadOpen)
    {
        <div class="thread-col">
            <ThreadPanel RootMessage="threadRootMessage"
                         ThreadMessages="threadMessages"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> channels = [];
    private int selectedChannelId;
    private Channel? selectedChannel;
    private List<Message> messages = [];
    private Dictionary<int, int> threadReplyCounts = [];
    private int skip;
    private bool isLoadingMore;
    private bool hasMoreMessages = true;

    private bool isThreadOpen;
    private int? activeThreadRootId;
    private Message? threadRootMessage;
    private List<Message> threadMessages = [];

    private MessageArea? messageAreaRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
        skip = 0;
        hasMoreMessages = true;
        messages = [];
        threadReplyCounts = [];
        CloseThreadInternal();

        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messages = loaded;
        skip = loaded.Count;
        hasMoreMessages = loaded.Count >= PageSize;
        BuildThreadReplyCounts();

        await ChatService.MarkChannelReadAsync(channelId);
        UpdateChannelUnread(channelId);

        messageAreaRef?.ScrollToBottom();
    }

    private async Task LoadMoreMessages()
    {
        if (isLoadingMore || !hasMoreMessages || selectedChannel is null) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(selectedChannelId, skip, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            skip += older.Count;
            BuildThreadReplyCounts();
        }
        hasMoreMessages = older.Count >= PageSize;
        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;

        var msg = await ChatService.SendMessageAsync(selectedChannelId, content, null);
        messages.Add(msg);
        skip++;
        messageAreaRef?.ScrollToBottom();
    }

    private async Task OpenThread(int rootMessageId)
    {
        activeThreadRootId = rootMessageId;
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        isThreadOpen = true;
    }

    private void CloseThread()
    {
        CloseThreadInternal();
        StateHasChanged();
    }

    private void CloseThreadInternal()
    {
        isThreadOpen = false;
        activeThreadRootId = null;
        threadRootMessage = null;
        threadMessages = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (activeThreadRootId is null || selectedChannel is null) return;

        var reply = await ChatService.SendMessageAsync(selectedChannelId, content, activeThreadRootId);
        threadMessages.Add(reply);

        // Update reply count in main view
        if (threadReplyCounts.ContainsKey(activeThreadRootId.Value))
            threadReplyCounts[activeThreadRootId.Value]++;
        else
            threadReplyCounts[activeThreadRootId.Value] = 1;
    }

    private async Task HandleReaction((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);

        // Optimistically update the UI
        var msg = messages.FirstOrDefault(m => m.Id == reaction.MessageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == reaction.Emoji);
            if (existing is not null)
            {
                existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(reaction.Emoji, ["You"]));
            }
        }
    }

    private void BuildThreadReplyCounts()
    {
        threadReplyCounts = messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }

    private void UpdateChannelUnread(int channelId)
    {
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var ch = channels[idx];
            channels[idx] = ch with { UnreadCount = 0 };
        }
    }
}

