.chat-container {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
}

.sidebar-col {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.main-col {
    flex: 1;
    min-width: 0;
    display: flex;
    flex-direction: column;
}

.main-col.with-thread {
    flex: 55;
}

.thread-col {
    width: 25%;
    min-width: 260px;
    max-width: 400px;
    flex-shrink: 0;
}

.empty-state {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #999;
    font-size: 1.1rem;
}

